judgeConfig.referenceSolution:
const fruits = [
  'Apple', 'Banana', 'Blueberry', 'Cherry', 'Coconut', 
  'Grape', 'Lemon', 'Mango', 'Orange', 'Peach', 
  'Pineapple', 'Raspberry', 'Strawberry', 'Watermelon'
];

const searchInput = document.getElementById('search-input');
const suggestionsList = document.getElementById('suggestions-list');

searchInput.addEventListener('input', () => {
  const query = searchInput.value.toLowerCase().trim();
  suggestionsList.innerHTML = '';

  if (!query) {
    suggestionsList.classList.add('hidden');
    return;
  }

  const matches = fruits.filter(f => f.toLowerCase().includes(query));
  if (matches.length === 0) {
    suggestionsList.classList.add('hidden');
    return;
  }

  matches.forEach(match => {
    const li = document.createElement('li');
    li.className = 'px-3 py-2 text-sm text-slate-300 hover:bg-indigo-600 hover:text-white cursor-pointer select-none';
    li.textContent = match;
    li.addEventListener('click', () => {
      searchInput.value = match;
      suggestionsList.classList.add('hidden');
      suggestionsList.innerHTML = '';
    });
    suggestionsList.appendChild(li);
  });

  suggestionsList.classList.remove('hidden');
});
